import unittest

class TestSolution(unittest.TestCase):
    def test_basic_anagrams(self):
        self.assertEqual(find_anagrams("listen", ["silent", "enlist", "hello", "tinsel"]),
                         ["silent", "enlist", "tinsel"])

    def test_some_match(self):
        self.assertEqual(find_anagrams("race", ["care", "acre", "rice"]),
                         ["care", "acre"])

    def test_no_match(self):
        self.assertEqual(find_anagrams("abc", ["def", "ghi"]), [])

    def test_hidden_empty_candidates(self):
        self.assertEqual(find_anagrams("hello", []), [])

    def test_hidden_case_insensitive(self):
        self.assertEqual(find_anagrams("Listen", ["Silent", "ENLIST"]),
                         ["Silent", "ENLIST"])

    def test_hidden_single_char(self):
        self.assertEqual(find_anagrams("a", ["a", "b", "A"]),
                         ["a", "A"])

    def test_hidden_same_word(self):
        self.assertEqual(find_anagrams("test", ["test"]), ["test"])

    def test_hidden_different_lengths(self):
        self.assertEqual(find_anagrams("ab", ["abc", "ba", "a"]),
                         ["ba"])

    def test_hidden_repeated_letters(self):
        self.assertEqual(find_anagrams("aab", ["aba", "baa", "aab", "ab", "aaab"]),
                         ["aba", "baa", "aab"])

if __name__ == '__main__':
    unittest.main()
